INSERT OR IGNORE INTO seasons (id, app_id, testament, name, slug, description, sort_order) VALUES ('s-ht-byzantine-empire', 'history-tea', 'old', 'Byzantine Empire', 'ht-byzantine-empire', 'Rome''s eastern half outlived the west by a thousand years. Intrigue, icons, and impossible sieges.', 60);
INSERT OR IGNORE INTO seasons (id, app_id, testament, name, slug, description, sort_order) VALUES ('s-ht-islamic-world', 'history-tea', 'old', 'Islamic World', 'ht-islamic-world', 'Caliphs, scholars, and a golden age of science when Europe was in the dark.', 70);
