INSERT OR IGNORE INTO seasons (id, app_id, testament, name, slug, description, sort_order) VALUES ('s-ht-medieval-asia', 'history-tea', 'old', 'Medieval Asia', 'ht-medieval-asia', 'Mongols, dynasties, and silk-road empires. The other half of the medieval world, often forgotten.', 90);
INSERT OR IGNORE INTO seasons (id, app_id, testament, name, slug, description, sort_order) VALUES ('s-ht-renaissance-and-reformation', 'history-tea', 'old', 'Renaissance & Reformation', 'ht-renaissance-and-reformation', 'Art, science, and a religious earthquake. Europe wakes up — and splits in two.', 100);
