INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-hammurabi', 'history-tea', 's-ht-ancient-mesopotamia', 'Hammurabi''s Code', 'hammurabis-code', 'The first time anyone wrote ''eye for an eye'' on a giant rock and said this is the law now. Carved into stone so nobody could argue.', 'stories/hammurabis-code/cover.webp', 100, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-gilgamesh', 'history-tea', 's-ht-ancient-mesopotamia', 'The Epic of Gilgamesh', 'epic-of-gilgamesh', 'The world''s oldest story. A tyrant king and a wild man become best friends, kill a forest god, then chase immortality. It does not go well.', 'stories/epic-of-gilgamesh/cover.webp', 101, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-sargon-of-akkad', 'history-tea', 's-ht-ancient-mesopotamia', 'Sargon of Akkad', 'sargon-of-akkad', 'An abandoned baby floats down a river in a basket and grows up to build the world''s first empire. Sound familiar?', 'stories/sargon-of-akkad/cover.webp', 102, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-ashurbanipals-library', 'history-tea', 's-ht-ancient-mesopotamia', 'Ashurbanipal''s Library', 'ashurbanipals-library', 'A brutal Assyrian king collects every book in the known world. The first librarian was a war criminal.', 'stories/ashurbanipals-library/cover.webp', 103, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-hanging-gardens-of-babylon', 'history-tea', 's-ht-ancient-mesopotamia', 'The Hanging Gardens of Babylon', 'hanging-gardens-of-babylon', 'Nebuchadnezzar builds his homesick wife a man-made mountain of plants. We''re still not 100% sure they actually existed.', 'stories/hanging-gardens-of-babylon/cover.webp', 104, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-cyrus-the-great', 'history-tea', 's-ht-ancient-mesopotamia', 'Cyrus the Great', 'cyrus-the-great', 'A Persian shepherd boy ends up freeing the Jews, conquering Babylon, and inventing human rights. Nobody saw it coming.', 'stories/cyrus-the-great/cover.webp', 105, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-darius-builds-persepolis', 'history-tea', 's-ht-ancient-mesopotamia', 'Darius Builds Persepolis', 'darius-builds-persepolis', 'The Persian king builds a city so beautiful that Alexander burns it down 200 years later out of pure jealousy.', 'stories/darius-builds-persepolis/cover.webp', 106, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-fall-of-babylon', 'history-tea', 's-ht-ancient-mesopotamia', 'The Fall of Babylon', 'fall-of-babylon', 'Cyrus diverts a river, walks his army into the city through the dry riverbed, and the party inside doesn''t even notice until it''s over.', 'stories/fall-of-babylon/cover.webp', 107, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-narmer-unites-egypt', 'history-tea', 's-ht-ancient-egypt', 'Narmer Unites Egypt', 'narmer-unites-egypt', 'One king, one crown, one giant slate showing him beating someone with a club. Welcome to Egypt.', 'stories/narmer-unites-egypt/cover.webp', 108, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-pyramids', 'history-tea', 's-ht-ancient-egypt', 'Building the Pyramids', 'building-the-pyramids', 'Tens of thousands of workers stack 2.3 million stone blocks for one guy''s tomb. Still the most impressive flex in human history.', 'stories/building-the-pyramids/cover.webp', 109, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-great-sphinx', 'history-tea', 's-ht-ancient-egypt', 'The Great Sphinx', 'the-great-sphinx', 'A 240-foot lion with a Pharaoh''s face stares into the desert for 4,500 years. Nobody is sure who built it or why.', 'stories/the-great-sphinx/cover.webp', 110, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-hatshepsut', 'history-tea', 's-ht-ancient-egypt', 'Hatshepsut, the Woman Pharaoh', 'hatshepsut-pharaoh', 'She crowns herself, wears a fake beard, rules for two decades, and builds half of Egypt. Then her stepson tries to erase her from history.', 'stories/hatshepsut-pharaoh/cover.webp', 111, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-akhenaten-the-heretic', 'history-tea', 's-ht-ancient-egypt', 'Akhenaten the Heretic', 'akhenaten-the-heretic', 'The Pharaoh who tried to delete every god except the sun. Egypt was so mad they tried to delete him right back.', 'stories/akhenaten-the-heretic/cover.webp', 112, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-tutankhamun', 'history-tea', 's-ht-ancient-egypt', 'Tutankhamun''s Tomb', 'tutankhamuns-tomb', 'A teenage Pharaoh dies mysteriously, gets buried with a solid gold mask, and stays hidden for 3,300 years until a guy with a candle finds him.', 'stories/tutankhamuns-tomb/cover.webp', 113, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-ramses-ii', 'history-tea', 's-ht-ancient-egypt', 'Ramses the Great', 'ramses-ii', 'Ruled for 66 years, fathered 100+ kids, fought the largest chariot battle in history, and put his face on every wall in Egypt.', 'stories/ramses-ii/cover.webp', 114, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-kadesh', 'history-tea', 's-ht-ancient-egypt', 'The Battle of Kadesh', 'battle-of-kadesh', 'Egypt vs the Hittites, 5,000 chariots in the desert. Both sides went home and told everyone they won. The first peace treaty in history followed.', 'stories/battle-of-kadesh/cover.webp', 115, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-cleopatra-caesar', 'history-tea', 's-ht-ancient-egypt', 'Cleopatra and Caesar', 'cleopatra-and-caesar', 'She has herself rolled up in a carpet and delivered to his bedroom. Within a year she''s pregnant and Egypt has a new ally.', 'stories/cleopatra-and-caesar/cover.webp', 116, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-cleopatra-and-antony', 'history-tea', 's-ht-ancient-egypt', 'Cleopatra and Antony', 'cleopatra-and-antony', 'Round two. She seduces Caesar''s right-hand man, they have three kids and a fleet, and basically declare war on Rome together. Bold strategy.', 'stories/cleopatra-and-antony/cover.webp', 117, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-actium', 'history-tea', 's-ht-ancient-egypt', 'The Battle of Actium', 'battle-of-actium', 'Cleopatra and Antony''s combined fleet meets Octavian''s at sea. Cleopatra panics, sails away, and Antony chases her. End of the Roman Republic.', 'stories/battle-of-actium/cover.webp', 118, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-death-of-cleopatra', 'history-tea', 's-ht-ancient-egypt', 'The Death of Cleopatra', 'death-of-cleopatra', 'She locks herself in her tomb with a basket of figs and an extremely angry snake. The last Pharaoh of Egypt picks her own ending.', 'stories/death-of-cleopatra/cover.webp', 119, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-library-of-alexandria-burns', 'history-tea', 's-ht-ancient-egypt', 'The Library of Alexandria Burns', 'library-of-alexandria-burns', 'The greatest collection of human knowledge ever assembled goes up in flames. We''re still mad about it 2,000 years later.', 'stories/library-of-alexandria-burns/cover.webp', 120, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-trojan-war', 'history-tea', 's-ht-ancient-greece', 'The Trojan War', 'the-trojan-war', 'A prince steals another king''s wife, so Greece spends ten years besieging Troy over it. Ends with a giant wooden horse and a massacre.', 'stories/the-trojan-war/cover.webp', 121, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-trojan-horse', 'history-tea', 's-ht-ancient-greece', 'The Trojan Horse', 'the-trojan-horse', 'Greeks pretend to give up, leave a giant wooden horse outside the gates, and the Trojans wheel it inside themselves. The original phishing attack.', 'stories/the-trojan-horse/cover.webp', 122, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-achilles-and-hector', 'history-tea', 's-ht-ancient-greece', 'Achilles and Hector', 'achilles-and-hector', 'Greece''s greatest warrior vs Troy''s greatest prince. One has plot armor everywhere except his heel. You can guess how this ends.', 'stories/achilles-and-hector/cover.webp', 123, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-odysseus-goes-home', 'history-tea', 's-ht-ancient-greece', 'Odysseus Goes Home', 'odysseus-goes-home', 'After ten years of war he tries to sail home. It takes another ten years, involves a Cyclops, a witch, and the dead. The original hero''s journey.', 'stories/odysseus-goes-home/cover.webp', 124, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-spartan-agoge', 'history-tea', 's-ht-ancient-greece', 'Sparta Builds Its War Machine', 'spartan-agoge', 'A whole society where boys are taken from their mothers at 7 to be turned into killing machines. Spoiler: it works extremely well.', 'stories/spartan-agoge/cover.webp', 125, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-draco-writes-the-laws', 'history-tea', 's-ht-ancient-greece', 'Draco Writes the Laws', 'draco-writes-the-laws', 'An Athenian writes laws so harsh that almost every crime is punishable by death. We still call brutal rules ''draconian'' because of him.', 'stories/draco-writes-the-laws/cover.webp', 126, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-marathon', 'history-tea', 's-ht-ancient-greece', 'The Battle of Marathon', 'battle-of-marathon', 'Outnumbered Athenians charge a much bigger Persian army and somehow win. A guy runs 26 miles to deliver the news, then drops dead.', 'stories/battle-of-marathon/cover.webp', 127, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-thermopylae', 'history-tea', 's-ht-ancient-greece', 'The 300 at Thermopylae', 'battle-of-thermopylae', 'King Leonidas and 300 Spartans hold a mountain pass against an entire Persian empire. They lose the battle but win the legend.', 'stories/battle-of-thermopylae/cover.webp', 128, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-salamis', 'history-tea', 's-ht-ancient-greece', 'The Battle of Salamis', 'battle-of-salamis', 'Greek triremes lure the Persian fleet into a narrow strait and obliterate them. Xerxes watches from a throne on a hill, horrified.', 'stories/battle-of-salamis/cover.webp', 129, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-pericles-golden-age', 'history-tea', 's-ht-ancient-greece', 'Pericles'' Golden Age', 'pericles-golden-age', 'Athens enters its glow-up era: democracy, the Parthenon, theatre, philosophy. Then a plague kills a third of the city, including Pericles.', 'stories/pericles-golden-age/cover.webp', 130, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-peloponnesian-war', 'history-tea', 's-ht-ancient-greece', 'The Peloponnesian War', 'peloponnesian-war', '27 years of Athens vs Sparta. Plagues, betrayals, exile, and one of the most disastrous military expeditions in history. Athens loses everything.', 'stories/peloponnesian-war/cover.webp', 131, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-socrates', 'history-tea', 's-ht-ancient-greece', 'Socrates Drinks the Hemlock', 'socrates-drinks-the-hemlock', 'An old man asks too many questions in public. Athens votes to make him drink poison. He calmly does it while his students cry.', 'stories/socrates-drinks-the-hemlock/cover.webp', 132, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-platos-academy', 'history-tea', 's-ht-ancient-greece', 'Plato Founds the Academy', 'platos-academy', 'The world''s first university opens in an olive grove outside Athens. Lasts 900 years, invents most of Western philosophy.', 'stories/platos-academy/cover.webp', 133, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-alexander', 'history-tea', 's-ht-ancient-greece', 'Alexander the Great', 'alexander-the-great', 'By age 32 he''s conquered most of the known world and reportedly cried because there was nothing left to conquer.', 'stories/alexander-the-great/cover.webp', 134, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-alexander-cuts-the-knot', 'history-tea', 's-ht-ancient-greece', 'Alexander Cuts the Gordian Knot', 'alexander-cuts-the-knot', 'Legend says whoever unties an impossible knot will rule Asia. Alexander pulls out his sword and cuts it in half. Cheating? Or genius?', 'stories/alexander-cuts-the-knot/cover.webp', 135, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-death-of-alexander', 'history-tea', 's-ht-ancient-greece', 'The Death of Alexander', 'death-of-alexander', 'He drops dead at 32 in Babylon. His generals immediately rip the empire to shreds fighting over the corpse.', 'stories/death-of-alexander/cover.webp', 136, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-archimedes-eureka', 'history-tea', 's-ht-ancient-greece', 'Archimedes Yells Eureka', 'archimedes-eureka', 'A Greek genius figures out displacement in the bath, runs naked through the streets shouting about it. Later dies because he''s too busy doing math to notice the Romans invading.', 'stories/archimedes-eureka/cover.webp', 137, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-romulus-remus', 'history-tea', 's-ht-roman-republic', 'Romulus and Remus', 'romulus-and-remus', 'Two abandoned brothers raised by a wolf decide to build a city. They argue about where. One murders the other. That city is Rome.', 'stories/romulus-and-remus/cover.webp', 138, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-rape-of-lucretia', 'history-tea', 's-ht-roman-republic', 'The Rape of Lucretia', 'the-rape-of-lucretia', 'A king''s son assaults a noblewoman, she takes her own life, and Rome overthrows the monarchy forever. The Republic is born from one act of evil.', 'stories/the-rape-of-lucretia/cover.webp', 139, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-cincinnatus-saves-rome', 'history-tea', 's-ht-roman-republic', 'Cincinnatus Saves Rome', 'cincinnatus-saves-rome', 'A retired farmer is begged to become dictator, defeats Rome''s enemies in 16 days, then goes back to his plow. Power? No thanks.', 'stories/cincinnatus-saves-rome/cover.webp', 140, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-gauls-sack-rome', 'history-tea', 's-ht-roman-republic', 'The Gauls Sack Rome', 'gauls-sack-rome', 'A horde of Celts walks into Rome and burns it down. Geese famously save the last hill. Rome never forgets, and never forgives.', 'stories/gauls-sack-rome/cover.webp', 141, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-hannibal', 'history-tea', 's-ht-roman-republic', 'Hannibal Crosses the Alps', 'hannibal-crosses-the-alps', 'A Carthaginian general marches an army and 37 war elephants over snowy mountains to surprise-attack Rome from the north. Rome did not see it coming.', 'stories/hannibal-crosses-the-alps/cover.webp', 142, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-cannae', 'history-tea', 's-ht-roman-republic', 'The Battle of Cannae', 'battle-of-cannae', 'Hannibal surrounds and slaughters 60,000 Romans in a single afternoon. Still studied as the perfect battle 2,200 years later.', 'stories/battle-of-cannae/cover.webp', 143, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-carthage-must-be-destroyed', 'history-tea', 's-ht-roman-republic', 'Carthage Must Be Destroyed', 'carthage-must-be-destroyed', 'An old senator ends every speech with the same line until Rome finally levels Carthage and salts the earth. Petty? Yes. Effective? Also yes.', 'stories/carthage-must-be-destroyed/cover.webp', 144, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-gracchi-brothers', 'history-tea', 's-ht-roman-republic', 'The Gracchi Brothers', 'the-gracchi-brothers', 'Two brothers try to give land back to the poor. The Senate murders them both, one after the other. The Republic starts to crack.', 'stories/the-gracchi-brothers/cover.webp', 145, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-sulla-marches-on-rome', 'history-tea', 's-ht-roman-republic', 'Sulla Marches on Rome', 'sulla-marches-on-rome', 'A Roman general turns his army around and invades his own city. The first time it happens. Definitely not the last.', 'stories/sulla-marches-on-rome/cover.webp', 146, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-spartacus-revolts', 'history-tea', 's-ht-roman-republic', 'Spartacus Revolts', 'spartacus-revolts', 'A Thracian gladiator and 70 friends escape a training school and end up leading 100,000 slaves in open war against Rome.', 'stories/spartacus-revolts/cover.webp', 147, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-first-triumvirate', 'history-tea', 's-ht-roman-republic', 'The First Triumvirate', 'first-triumvirate', 'Caesar, Pompey, and Crassus quietly carve up the Republic between themselves over wine. Three friends. Soon to be three enemies.', 'stories/first-triumvirate/cover.webp', 148, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-caesar-conquers-gaul', 'history-tea', 's-ht-roman-republic', 'Caesar Conquers Gaul', 'caesar-conquers-gaul', 'Eight years, a million dead, another million enslaved. He writes his own bestselling book about it. The man knows branding.', 'stories/caesar-conquers-gaul/cover.webp', 149, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-rubicon', 'history-tea', 's-ht-roman-republic', 'Caesar Crosses the Rubicon', 'caesar-crosses-the-rubicon', 'Ordered to disband his army, Caesar instead marches it across a tiny river and starts a civil war. ''The die is cast.''', 'stories/caesar-crosses-the-rubicon/cover.webp', 150, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-ides-of-march', 'history-tea', 's-ht-roman-republic', 'The Ides of March', 'ides-of-march', 'Julius Caesar walks into the Roman Senate and never walks out. His closest friends turn on him in the most famous political betrayal in history. ''Et tu, Brute?''', 'stories/ides-of-march/cover.webp', 151, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-ciceros-death', 'history-tea', 's-ht-roman-republic', 'Cicero''s Death', 'ciceros-death', 'Rome''s greatest orator gets on the wrong side of Mark Antony. They cut off his head and hands and nail them to the Senate doors.', 'stories/ciceros-death/cover.webp', 152, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-augustus-becomes-emperor', 'history-tea', 's-ht-roman-empire', 'Augustus Becomes Emperor', 'augustus-becomes-emperor', 'Caesar''s quiet 18-year-old nephew somehow outplays everyone, ends 100 years of civil war, and quietly turns Rome into an empire.', 'stories/augustus-becomes-emperor/cover.webp', 153, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-varus-loses-the-legions', 'history-tea', 's-ht-roman-empire', 'Varus Loses the Legions', 'varus-loses-the-legions', 'Three Roman legions get ambushed in a German forest and wiped out. Augustus reportedly walks the palace banging his head, yelling ''Varus, give me back my legions!''', 'stories/varus-loses-the-legions/cover.webp', 154, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-tiberius-on-capri', 'history-tea', 's-ht-roman-empire', 'Tiberius on Capri', 'tiberius-on-capri', 'The emperor gets bored of Rome, moves to a private island, and lets his henchmen run the city. Things get extremely weird.', 'stories/tiberius-on-capri/cover.webp', 155, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-caligulas-madness', 'history-tea', 's-ht-roman-empire', 'Caligula Goes Mad', 'caligulas-madness', 'He starts strong, gets a fever, and emerges convinced he''s a god. Tries to make his horse a senator. Lasts three years before the guards stab him.', 'stories/caligulas-madness/cover.webp', 156, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-claudius-the-unlikely-emperor', 'history-tea', 's-ht-roman-empire', 'Claudius the Unlikely Emperor', 'claudius-the-unlikely-emperor', 'Everyone thought the limping, stuttering uncle was harmless. Then the guards drag him from behind a curtain and crown him by accident. He''s actually pretty good at it.', 'stories/claudius-the-unlikely-emperor/cover.webp', 157, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-boudiccas-revolt', 'history-tea', 's-ht-roman-empire', 'Boudicca''s Revolt', 'boudiccas-revolt', 'A British queen leads 100,000 furious Celts and burns three Roman cities to the ground. Almost kicks Rome out of Britain entirely.', 'stories/boudiccas-revolt/cover.webp', 158, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-nero', 'history-tea', 's-ht-roman-empire', 'Nero Burns Rome', 'nero-burns-rome', 'Half the city goes up in flames. Nero allegedly plays music while it burns, then blames Christians and starts the world''s first crusade against them.', 'stories/nero-burns-rome/cover.webp', 159, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-year-of-the-four-emperors', 'history-tea', 's-ht-roman-empire', 'The Year of the Four Emperors', 'year-of-the-four-emperors', 'In 12 months, Rome cycles through four emperors. Three are murdered. The fourth, Vespasian, finally just shows up with an army and ends it.', 'stories/year-of-the-four-emperors/cover.webp', 160, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-destruction-of-jerusalem', 'history-tea', 's-ht-roman-empire', 'The Destruction of Jerusalem', 'destruction-of-jerusalem', 'Vespasian''s son Titus levels the Temple after a brutal siege. The Jewish diaspora begins. Rome builds an arch to brag about it.', 'stories/destruction-of-jerusalem/cover.webp', 161, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-pompeii', 'history-tea', 's-ht-roman-empire', 'Pompeii Destroyed', 'pompeii-destroyed', 'Mount Vesuvius erupts and buries an entire Roman city under 20 feet of ash in hours. We can still see the people frozen mid-step.', 'stories/pompeii-destroyed/cover.webp', 162, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-trajan-builds-the-empire', 'history-tea', 's-ht-roman-empire', 'Trajan Builds the Empire', 'trajan-builds-the-empire', 'Rome hits its biggest size ever under a Spanish-born emperor who actually likes the people. Builds a column so tall you need binoculars to see the top.', 'stories/trajan-builds-the-empire/cover.webp', 163, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-hadrians-wall', 'history-tea', 's-ht-roman-empire', 'Hadrian''s Wall', 'hadrians-wall', 'Rome decides Britain north of a certain line is just not worth it and builds a 73-mile wall to keep the Picts out. Still standing.', 'stories/hadrians-wall/cover.webp', 164, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-marcus-aurelius-philosopher-king', 'history-tea', 's-ht-roman-empire', 'Marcus Aurelius, Philosopher King', 'marcus-aurelius-philosopher-king', 'A Roman emperor writes a private journal about being a better person while fighting a 14-year war on the frontier. Still a bestseller.', 'stories/marcus-aurelius-philosopher-king/cover.webp', 165, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-commodus-the-gladiator-emperor', 'history-tea', 's-ht-roman-empire', 'Commodus the Gladiator Emperor', 'commodus-the-gladiator-emperor', 'Marcus Aurelius''s son thinks he''s Hercules and fights in the Colosseum himself. His mistress and his trainer eventually strangle him in the bath.', 'stories/commodus-the-gladiator-emperor/cover.webp', 166, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-crisis-of-the-third-century', 'history-tea', 's-ht-roman-empire', 'The Crisis of the Third Century', 'crisis-of-the-third-century', '50 years, 26 emperors, plague, hyperinflation, barbarian invasions, and the empire splits into three. Rome should not have survived this.', 'stories/crisis-of-the-third-century/cover.webp', 167, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-constantine-converts', 'history-tea', 's-ht-roman-empire', 'Constantine Converts', 'constantine-converts', 'Before a battle he sees a cross in the sky and a voice says ''in this sign, conquer.'' He wins, and Christianity goes from persecuted cult to imperial religion.', 'stories/constantine-converts/cover.webp', 168, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-council-of-nicaea', 'history-tea', 's-ht-roman-empire', 'The Council of Nicaea', 'council-of-nicaea', 'Constantine locks 300 bishops in a room until they agree on what Christians actually believe. The result still gets recited in churches today.', 'stories/council-of-nicaea/cover.webp', 169, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-julian-the-apostate', 'history-tea', 's-ht-roman-empire', 'Julian the Apostate', 'julian-the-apostate', 'An emperor tries to undo Constantine''s revolution and bring back the old gods. Lasts 20 months before dying in battle in Persia.', 'stories/julian-the-apostate/cover.webp', 170, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-sack-of-rome-410', 'history-tea', 's-ht-roman-empire', 'The Sack of Rome', 'sack-of-rome-410', 'The Visigoths walk into the Eternal City and loot it for three days. Rome hadn''t been taken in 800 years. The world is in shock.', 'stories/sack-of-rome-410/cover.webp', 171, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-attila-the-hun', 'history-tea', 's-ht-roman-empire', 'Attila the Hun', 'attila-the-hun', 'Sweeps out of the steppe and terrorizes both halves of the Roman empire. Dies on his wedding night from a nosebleed. Anticlimactic.', 'stories/attila-the-hun/cover.webp', 172, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-fall-of-rome', 'history-tea', 's-ht-roman-empire', 'The Fall of Rome', 'fall-of-rome', 'A Germanic warlord politely deposes the last Roman emperor, a teenager named Romulus. 1,200 years end with a whimper.', 'stories/fall-of-rome/cover.webp', 173, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-justinian-and-theodora', 'history-tea', 's-ht-byzantine-empire', 'Justinian and Theodora', 'justinian-and-theodora', 'An emperor marries a former actress, and together they save Constantinople from a riot, rebuild the legal code, and almost reconquer Rome.', 'stories/justinian-and-theodora/cover.webp', 174, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-nika-riots', 'history-tea', 's-ht-byzantine-empire', 'The Nika Riots', 'the-nika-riots', 'Two rival sports fan groups team up and try to overthrow Justinian. Theodora tells him to stay and fight. 30,000 rioters die in a single day.', 'stories/the-nika-riots/cover.webp', 175, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-hagia-sophia-rises', 'history-tea', 's-ht-byzantine-empire', 'Hagia Sophia Rises', 'hagia-sophia-rises', 'Justinian builds a dome so big and so daring that for 1,000 years nobody could match it. He looks up at it and says ''Solomon, I have outdone you.''', 'stories/hagia-sophia-rises/cover.webp', 176, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-justinian-plague', 'history-tea', 's-ht-byzantine-empire', 'The Plague of Justinian', 'justinian-plague', 'Bubonic plague hits Constantinople and kills 25-50 million people across the empire. The first pandemic on this scale in recorded history.', 'stories/justinian-plague/cover.webp', 177, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-iconoclast-crisis', 'history-tea', 's-ht-byzantine-empire', 'The Iconoclast Crisis', 'iconoclast-crisis', 'Two emperors decide religious art is a sin and order every icon in the empire smashed. The Church loses its mind. Lasts 100 years.', 'stories/iconoclast-crisis/cover.webp', 178, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-manzikert', 'history-tea', 's-ht-byzantine-empire', 'The Battle of Manzikert', 'battle-of-manzikert', 'Byzantine emperor walks into a Turkish ambush, loses everything, and the empire never recovers. The slow death of Byzantium begins.', 'stories/battle-of-manzikert/cover.webp', 179, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-fall-constantinople', 'history-tea', 's-ht-byzantine-empire', 'The Fall of Constantinople', 'fall-of-constantinople', 'After 53 days of bombardment with the biggest cannons ever made, the 1,100-year-old city falls to the Ottoman Turks. The Middle Ages end here.', 'stories/fall-of-constantinople/cover.webp', 180, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-muhammads-revelation', 'history-tea', 's-ht-islamic-world', 'Muhammad''s First Revelation', 'muhammads-revelation', 'A 40-year-old merchant goes to a cave to think and an angel grabs him and tells him to recite. Islam begins.', 'stories/muhammads-revelation/cover.webp', 181, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-hijra', 'history-tea', 's-ht-islamic-world', 'The Hijra', 'the-hijra', 'Muhammad and his followers flee Mecca for Medina. The Islamic calendar starts from this exact moment.', 'stories/the-hijra/cover.webp', 182, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-badr', 'history-tea', 's-ht-islamic-world', 'The Battle of Badr', 'battle-of-badr', '313 outnumbered Muslims defeat 1,000 Meccans in the desert. Becomes the founding military legend of Islam.', 'stories/battle-of-badr/cover.webp', 183, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-karbala', 'history-tea', 's-ht-islamic-world', 'The Battle of Karbala', 'battle-of-karbala', 'The Prophet''s grandson Hussein and 72 followers are killed in the desert by an Umayyad army. The wound that splits Islam into Sunni and Shia.', 'stories/battle-of-karbala/cover.webp', 184, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-umayyads-build-an-empire', 'history-tea', 's-ht-islamic-world', 'The Umayyads Build an Empire', 'umayyads-build-an-empire', 'Within 100 years of Muhammad''s death, the Caliphate stretches from Spain to India. Largest empire the world had ever seen.', 'stories/umayyads-build-an-empire/cover.webp', 185, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-house-of-wisdom', 'history-tea', 's-ht-islamic-world', 'The House of Wisdom', 'house-of-wisdom', 'Baghdad becomes the brain of the world: algebra, astronomy, medicine, every Greek text translated and improved. Then the Mongols torch it.', 'stories/house-of-wisdom/cover.webp', 186, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-saladin-retakes-jerusalem', 'history-tea', 's-ht-islamic-world', 'Saladin Retakes Jerusalem', 'saladin-retakes-jerusalem', 'After 88 years of Crusader rule, a Kurdish sultan walks back in. Famously refuses to massacre civilians, even though the Crusaders did exactly that in 1099.', 'stories/saladin-retakes-jerusalem/cover.webp', 187, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-mongols-sack-baghdad', 'history-tea', 's-ht-islamic-world', 'The Mongols Sack Baghdad', 'mongols-sack-baghdad', 'The Tigris runs black with ink from books and red with blood. The Islamic Golden Age ends in a single week.', 'stories/mongols-sack-baghdad/cover.webp', 188, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-charlemagne-crowned', 'history-tea', 's-ht-medieval-europe', 'Charlemagne is Crowned', 'charlemagne-crowned', 'On Christmas Day, the Pope drops a crown on a Frankish king''s head and declares the Roman Empire is back. Charlemagne pretends to be surprised.', 'stories/charlemagne-crowned/cover.webp', 189, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-tours', 'history-tea', 's-ht-medieval-europe', 'The Battle of Tours', 'battle-of-tours', 'Charles Martel and the Franks stop a massive Umayyad invasion in central France. Basically decides whether Europe stays Christian.', 'stories/battle-of-tours/cover.webp', 190, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-lindisfarne', 'history-tea', 's-ht-medieval-europe', 'The Vikings Raid Lindisfarne', 'vikings-raid-lindisfarne', 'Long ships appear out of the fog, monks get slaughtered in their own monastery, and Europe learns a new word: Viking.', 'stories/vikings-raid-lindisfarne/cover.webp', 191, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-alfred-the-great', 'history-tea', 's-ht-medieval-europe', 'Alfred the Great', 'alfred-the-great', 'An English king on the run from the Vikings hides in a swamp, regroups, and ends up the only English ruler called ''the Great.''', 'stories/alfred-the-great/cover.webp', 192, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-hastings', 'history-tea', 's-ht-medieval-europe', 'The Battle of Hastings', 'battle-of-hastings', 'William of Normandy invades England, fakes a retreat, and an arrow goes through King Harold''s eye. England is never the same.', 'stories/battle-of-hastings/cover.webp', 193, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-first-crusade', 'history-tea', 's-ht-medieval-europe', 'The First Crusade', 'first-crusade', 'The Pope calls for holy war. 60,000 Europeans march 2,000 miles, take Jerusalem, and massacre everyone inside. The blood reportedly came up to the horses'' knees.', 'stories/first-crusade/cover.webp', 194, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-thomas-becket-murdered', 'history-tea', 's-ht-medieval-europe', 'Thomas Becket Murdered', 'thomas-becket-murdered', 'King Henry II yells ''will no one rid me of this turbulent priest?'' Four knights take him literally and murder the archbishop in his own cathedral.', 'stories/thomas-becket-murdered/cover.webp', 195, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-richard-the-lionheart', 'history-tea', 's-ht-medieval-europe', 'Richard the Lionheart', 'richard-the-lionheart', 'An English king who barely speaks English spends his entire reign on Crusade or in prison. His brother John runs the country into the ground at home.', 'stories/richard-the-lionheart/cover.webp', 196, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-magna-carta', 'history-tea', 's-ht-medieval-europe', 'The Magna Carta', 'magna-carta', 'Furious barons corner King John in a meadow and force him to sign away his absolute power. The first paper limit on a king. Ever.', 'stories/magna-carta/cover.webp', 197, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-fourth-crusade-sacks-constantinople', 'history-tea', 's-ht-medieval-europe', 'The Fourth Crusade Sacks Constantinople', 'fourth-crusade-sacks-constantinople', 'Crusaders heading for Jerusalem run out of money, get hired by Venice, and sack the biggest Christian city in the world instead.', 'stories/fourth-crusade-sacks-constantinople/cover.webp', 198, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-templars-destroyed', 'history-tea', 's-ht-medieval-europe', 'The Templars Destroyed', 'templars-destroyed', 'The richest knights in Europe get arrested in one coordinated raid on Friday the 13th. Their leader is burned alive. The French king takes their gold.', 'stories/templars-destroyed/cover.webp', 199, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-black-death', 'history-tea', 's-ht-medieval-europe', 'The Black Death', 'the-black-death', 'A plague riding on rats and fleas wipes out a third of Europe in four years. People paint dancing skeletons everywhere.', 'stories/the-black-death/cover.webp', 200, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-hundred-years-war', 'history-tea', 's-ht-medieval-europe', 'The Hundred Years'' War', 'hundred-years-war', 'England and France fight over the French throne for 116 years. Longbows, knights, plague, and Joan of Arc. Nobody really wins.', 'stories/hundred-years-war/cover.webp', 201, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-joan-of-arc', 'history-tea', 's-ht-medieval-europe', 'Joan of Arc', 'joan-of-arc', 'An illiterate teenage farmgirl says God told her to lead the French army. She does. The English burn her alive at 19. Centuries later they make her a saint.', 'stories/joan-of-arc/cover.webp', 202, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-wars-of-the-roses', 'history-tea', 's-ht-medieval-europe', 'The Wars of the Roses', 'wars-of-the-roses', 'Two branches of the same English royal family kill each other for 32 years over which color rose is better. Game of Thrones is basically this.', 'stories/wars-of-the-roses/cover.webp', 203, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-genghis-khan', 'history-tea', 's-ht-medieval-asia', 'Genghis Khan Rises', 'genghis-khan-rises', 'An abandoned boy on the Mongolian steppe unites every warring tribe and ends up conquering more land than any human in history.', 'stories/genghis-khan-rises/cover.webp', 204, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-kublai-khan-and-yuan', 'history-tea', 's-ht-medieval-asia', 'Kublai Khan Founds the Yuan', 'kublai-khan-and-yuan', 'Genghis''s grandson finishes the job in China and rules from a city Marco Polo calls the most magnificent on earth.', 'stories/kublai-khan-and-yuan/cover.webp', 205, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-marco-polo-in-china', 'history-tea', 's-ht-medieval-asia', 'Marco Polo in China', 'marco-polo-in-china', 'A Venetian teenager travels the Silk Road, lives in Kublai Khan''s court for 17 years, and comes home to a Europe that thinks he''s making it all up.', 'stories/marco-polo-in-china/cover.webp', 206, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-kamikaze-saves-japan', 'history-tea', 's-ht-medieval-asia', 'The Kamikaze Saves Japan', 'kamikaze-saves-japan', 'The Mongols try to invade Japan twice. Both times a typhoon shows up and shreds the fleet. The Japanese name the wind ''divine.''', 'stories/kamikaze-saves-japan/cover.webp', 207, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-ming-dynasty-rises', 'history-tea', 's-ht-medieval-asia', 'The Ming Dynasty Rises', 'ming-dynasty-rises', 'A Chinese peasant overthrows the Mongols and founds a dynasty that will rebuild the Great Wall and run the world''s biggest fleet.', 'stories/ming-dynasty-rises/cover.webp', 208, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-zheng-he-treasure-fleet', 'history-tea', 's-ht-medieval-asia', 'Zheng He''s Treasure Fleet', 'zheng-he-treasure-fleet', 'A Chinese eunuch admiral leads 300 ships and 28,000 men across the Indian Ocean. Then China decides exploring isn''t worth it and burns the fleet.', 'stories/zheng-he-treasure-fleet/cover.webp', 209, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-tale-of-genji', 'history-tea', 's-ht-medieval-asia', 'The Tale of Genji', 'tale-of-genji', 'A noblewoman in Kyoto writes the world''s first psychological novel about a beautiful prince and his messy love life. 1,000 years before the form catches on.', 'stories/tale-of-genji/cover.webp', 210, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-samurai-code', 'history-tea', 's-ht-medieval-asia', 'The Samurai Code', 'samurai-code', 'Japan''s warrior class decides loyalty, honor, and a clean sword cut are more important than life itself. Then they enforce it for 700 years.', 'stories/samurai-code/cover.webp', 211, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-angkor-wat-built', 'history-tea', 's-ht-medieval-asia', 'Angkor Wat Built', 'angkor-wat-built', 'A Khmer king builds the largest religious monument on earth, then loses it to the jungle for 400 years.', 'stories/angkor-wat-built/cover.webp', 212, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-delhi-sultanate', 'history-tea', 's-ht-medieval-asia', 'The Delhi Sultanate', 'delhi-sultanate', 'A former slave founds a Muslim dynasty in India that lasts 320 years and includes a sultan who reportedly tried to move the capital to a different city. Twice.', 'stories/delhi-sultanate/cover.webp', 213, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-medici-rise', 'history-tea', 's-ht-renaissance-and-reformation', 'The Medici Rise', 'medici-rise', 'A family of bankers takes over Florence, funds the Renaissance, and produces three popes and two queens of France. All from interest.', 'stories/medici-rise/cover.webp', 214, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-fall-of-constantinople-renaissance-trigger', 'history-tea', 's-ht-renaissance-and-reformation', 'Greek Scholars Flee West', 'fall-of-constantinople-renaissance-trigger', 'After Constantinople falls, refugee Greek scholars pour into Italy carrying ancient manuscripts. The Renaissance suddenly has rocket fuel.', 'stories/fall-of-constantinople-renaissance-trigger/cover.webp', 215, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-gutenberg-prints-the-bible', 'history-tea', 's-ht-renaissance-and-reformation', 'Gutenberg Prints the Bible', 'gutenberg-prints-the-bible', 'A German tinkerer builds the printing press, mass-produces the Bible, and accidentally invents mass communication, science, and revolution.', 'stories/gutenberg-prints-the-bible/cover.webp', 216, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-savonarolas-bonfire', 'history-tea', 's-ht-renaissance-and-reformation', 'Savonarola''s Bonfire of the Vanities', 'savonarolas-bonfire', 'A Dominican monk takes over Florence and burns books, art, and makeup in a giant pile. Then Florence burns him.', 'stories/savonarolas-bonfire/cover.webp', 217, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-borgia-popes', 'history-tea', 's-ht-renaissance-and-reformation', 'The Borgia Popes', 'borgia-popes', 'A Spanish family buys the papacy and uses it to commit poisoning, incest rumors, and political assassinations. Cesare Borgia inspires Machiavelli.', 'stories/borgia-popes/cover.webp', 218, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-da-vinci', 'history-tea', 's-ht-renaissance-and-reformation', 'Leonardo da Vinci', 'leonardo-da-vinci', 'Paints the Mona Lisa, designs flying machines, dissects corpses, writes backwards. One man casually invents the future in his spare time.', 'stories/leonardo-da-vinci/cover.webp', 219, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-michelangelo-and-the-sistine', 'history-tea', 's-ht-renaissance-and-reformation', 'Michelangelo and the Sistine Chapel', 'michelangelo-and-the-sistine', 'He hates painting, hates the Pope, and lies on his back for four years anyway. Result: the most famous ceiling on earth.', 'stories/michelangelo-and-the-sistine/cover.webp', 220, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-machiavelli-writes-the-prince', 'history-tea', 's-ht-renaissance-and-reformation', 'Machiavelli Writes The Prince', 'machiavelli-writes-the-prince', 'A fired Florentine bureaucrat writes a how-to manual for ruthless rulers, hoping to get his job back. Five centuries later it''s still required reading.', 'stories/machiavelli-writes-the-prince/cover.webp', 221, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-luther', 'history-tea', 's-ht-renaissance-and-reformation', 'Luther''s 95 Theses', 'luthers-95-theses', 'A German monk nails a list of complaints to a church door. Within a few years half of Europe has broken with Rome.', 'stories/luthers-95-theses/cover.webp', 222, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-henry-viii', 'history-tea', 's-ht-renaissance-and-reformation', 'Henry VIII and His Six Wives', 'henry-viii-six-wives', 'Wants a son so badly he breaks with the Pope, beheads two wives, divorces two more, and ruins his own legacy. Get him out of his marriage.', 'stories/henry-viii-six-wives/cover.webp', 223, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-anne-boleyn-beheaded', 'history-tea', 's-ht-renaissance-and-reformation', 'Anne Boleyn Beheaded', 'anne-boleyn-beheaded', 'She made a king break with Rome to marry her. Three years later he had her head cut off with a French sword for a fake adultery charge.', 'stories/anne-boleyn-beheaded/cover.webp', 224, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-bloody-mary', 'history-tea', 's-ht-renaissance-and-reformation', 'Bloody Mary', 'bloody-mary', 'Henry VIII''s Catholic daughter takes the throne and burns 280 Protestants alive trying to drag England back to Rome. Dies childless five years later.', 'stories/bloody-mary/cover.webp', 225, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-elizabeth-i', 'history-tea', 's-ht-renaissance-and-reformation', 'Elizabeth I', 'elizabeth-i', 'The ''Virgin Queen'' rules England for 45 years, never marries, defeats the Spanish Armada, and turns a backwater into a superpower.', 'stories/elizabeth-i/cover.webp', 226, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-mary-queen-of-scots', 'history-tea', 's-ht-renaissance-and-reformation', 'Mary Queen of Scots', 'mary-queen-of-scots', 'Three husbands, multiple plots, 19 years in English prison, and finally beheaded by her own cousin Elizabeth. The most cinematic monarch ever.', 'stories/mary-queen-of-scots/cover.webp', 227, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-spanish-armada', 'history-tea', 's-ht-renaissance-and-reformation', 'The Spanish Armada', 'spanish-armada', 'Spain sends 130 ships to invade England. Storms, fireships, and English cannons send most of them to the bottom of the sea.', 'stories/spanish-armada/cover.webp', 228, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-gunpowder-plot', 'history-tea', 's-ht-renaissance-and-reformation', 'The Gunpowder Plot', 'gunpowder-plot', 'Guy Fawkes and friends try to blow up Parliament with the king inside. They get caught the night before. The UK still burns Fawkes in effigy every year.', 'stories/gunpowder-plot/cover.webp', 229, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-columbus', 'history-tea', 's-ht-age-of-exploration', 'Columbus Sails the Ocean Blue', 'columbus-1492', 'An Italian sailor convinces Spain to fund a shortcut to India. He misses by an entire continent, calls the locals ''Indians,'' and changes the world.', 'stories/columbus-1492/cover.webp', 230, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-vasco-da-gama-india', 'history-tea', 's-ht-age-of-exploration', 'Vasco da Gama Reaches India', 'vasco-da-gama-india', 'A Portuguese captain finally finds the actual sea route to India. Returns home with cargo worth 60 times the cost of the voyage.', 'stories/vasco-da-gama-india/cover.webp', 231, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-magellan-circumnavigates', 'history-tea', 's-ht-age-of-exploration', 'Magellan Circumnavigates the Globe', 'magellan-circumnavigates', 'He sets out with 5 ships and 270 men. Three years later, 1 ship and 18 starving survivors limp back. Magellan is not one of them.', 'stories/magellan-circumnavigates/cover.webp', 232, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-cortes', 'history-tea', 's-ht-age-of-exploration', 'Cortés Conquers the Aztecs', 'cortes-conquers-the-aztecs', '600 Spaniards walk into the Aztec capital, take the emperor hostage, and burn their own ships so nobody can retreat. Two years later, the empire is gone.', 'stories/cortes-conquers-the-aztecs/cover.webp', 233, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-fall-of-tenochtitlan', 'history-tea', 's-ht-age-of-exploration', 'The Fall of Tenochtitlan', 'fall-of-tenochtitlan', 'After a brutal 75-day siege, the largest city in the Americas falls. Mexico City rises on its bones.', 'stories/fall-of-tenochtitlan/cover.webp', 234, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-pizarro-and-the-inca', 'history-tea', 's-ht-age-of-exploration', 'Pizarro and the Inca', 'pizarro-and-the-inca', '168 Spaniards walk up the Andes, kidnap the Inca emperor in front of his army, and take a room full of gold as ransom. Then kill him anyway.', 'stories/pizarro-and-the-inca/cover.webp', 235, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-atahualpas-ransom', 'history-tea', 's-ht-age-of-exploration', 'Atahualpa''s Ransom', 'atahualpas-ransom', 'The Inca emperor fills a giant room twice with gold and silver to buy his freedom. The Spanish take the gold and execute him anyway.', 'stories/atahualpas-ransom/cover.webp', 236, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-drake-circumnavigates', 'history-tea', 's-ht-age-of-exploration', 'Drake Circumnavigates', 'drake-circumnavigates', 'An English pirate-captain robs Spanish ships all the way around the world and comes home loaded with treasure. Elizabeth I knights him on his own deck.', 'stories/drake-circumnavigates/cover.webp', 237, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-jamestown-founded', 'history-tea', 's-ht-age-of-exploration', 'Jamestown Founded', 'jamestown-founded', '104 Englishmen show up in Virginia thinking they''ll find gold. Most starve to death. The few who survive accidentally start America.', 'stories/jamestown-founded/cover.webp', 238, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-mayflower-lands', 'history-tea', 's-ht-age-of-exploration', 'The Mayflower Lands', 'mayflower-lands', 'Religious separatists aiming for Virginia get blown off course and land in Massachusetts. Half of them die that first winter.', 'stories/mayflower-lands/cover.webp', 239, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-thirty-years-war', 'history-tea', 's-ht-17th-century', 'The Thirty Years'' War', 'thirty-years-war', 'What starts as Catholics vs Protestants in Bohemia ends with most of Central Europe in ruins and 8 million dead. Religion was just the excuse.', 'stories/thirty-years-war/cover.webp', 240, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-galileos-trial', 'history-tea', 's-ht-17th-century', 'Galileo''s Trial', 'galileos-trial', 'He says the Earth orbits the Sun. The Church says recant or die. He recants, mutters ''and yet it moves'' on the way out, and gets house arrest forever.', 'stories/galileos-trial/cover.webp', 241, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-english-civil-war', 'history-tea', 's-ht-17th-century', 'The English Civil War', 'english-civil-war', 'King Charles I tries to rule without Parliament. Parliament raises an army. Nine years later the king''s head rolls off a block in front of his own palace.', 'stories/english-civil-war/cover.webp', 242, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-execution-of-charles-i', 'history-tea', 's-ht-17th-century', 'The Execution of Charles I', 'execution-of-charles-i', 'First time in history a European king is publicly tried, convicted, and executed by his own people. Even his enemies are shocked.', 'stories/execution-of-charles-i/cover.webp', 243, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-cromwell-rules', 'history-tea', 's-ht-17th-century', 'Cromwell Rules', 'cromwell-rules', 'An English Puritan general bans Christmas, theatre, and basically having fun. After he dies, the country digs him up just to behead his corpse.', 'stories/cromwell-rules/cover.webp', 244, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-louis-xiv-versailles', 'history-tea', 's-ht-17th-century', 'Louis XIV Builds Versailles', 'louis-xiv-versailles', 'The Sun King turns a hunting lodge into a 2,000-room palace and forces every powerful French noble to live there so he can keep an eye on them.', 'stories/louis-xiv-versailles/cover.webp', 245, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-great-fire-of-london', 'history-tea', 's-ht-17th-century', 'The Great Fire of London', 'great-fire-of-london', 'A bakery fire spreads for four days and burns down 13,000 houses and 87 churches. Silver lining: kills off the plague rats too.', 'stories/great-fire-of-london/cover.webp', 246, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-newtons-apple', 'history-tea', 's-ht-17th-century', 'Newton''s Apple', 'newtons-apple', 'A young Cambridge student goes home during plague lockdown and basically invents calculus, optics, and gravity in 18 months.', 'stories/newtons-apple/cover.webp', 247, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-salem', 'history-tea', 's-ht-17th-century', 'The Salem Witch Trials', 'salem-witch-trials', 'Two girls in colonial Massachusetts start having fits and accusing their neighbors. 19 people get hanged before the adults come to their senses.', 'stories/salem-witch-trials/cover.webp', 248, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-peter-the-great', 'history-tea', 's-ht-enlightenment-and-revolutions', 'Peter the Great', 'peter-the-great', 'A 6''8 Russian tsar travels Europe undercover, learns shipbuilding, comes home, shaves all the boyars'' beards by force, and builds St. Petersburg in a swamp.', 'stories/peter-the-great/cover.webp', 249, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-catherine-the-great', 'history-tea', 's-ht-enlightenment-and-revolutions', 'Catherine the Great', 'catherine-the-great', 'A German princess marries the wrong tsar, has him deposed (and possibly killed), then rules Russia for 34 years and almost doubles its size.', 'stories/catherine-the-great/cover.webp', 250, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-voltaire-and-the-philosophes', 'history-tea', 's-ht-enlightenment-and-revolutions', 'Voltaire and the Philosophes', 'voltaire-and-the-philosophes', 'A bunch of French intellectuals get exiled, locked up, and bestselling for arguing that maybe kings and priests aren''t always right.', 'stories/voltaire-and-the-philosophes/cover.webp', 251, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-seven-years-war', 'history-tea', 's-ht-enlightenment-and-revolutions', 'The Seven Years'' War', 'seven-years-war', 'The first true world war. Britain vs France in Europe, North America, India, and the Caribbean. Britain wins, gets Canada, and accidentally bankrupts itself.', 'stories/seven-years-war/cover.webp', 252, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-boston-tea', 'history-tea', 's-ht-enlightenment-and-revolutions', 'The Boston Tea Party', 'boston-tea-party', 'Colonists dressed as Mohawks dump 342 chests of British tea into Boston Harbor. The most expensive tantrum in history.', 'stories/boston-tea-party/cover.webp', 253, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-declaration-of-independence', 'history-tea', 's-ht-enlightenment-and-revolutions', 'The Declaration of Independence', 'declaration-of-independence', 'Thirteen tiny colonies write a breakup letter to the world''s biggest empire. ''All men are created equal'' becomes a problem they don''t fully solve.', 'stories/declaration-of-independence/cover.webp', 254, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-washington-crosses-the-delaware', 'history-tea', 's-ht-enlightenment-and-revolutions', 'Washington Crosses the Delaware', 'washington-crosses-the-delaware', 'On Christmas night, in a snowstorm, Washington rows across an icy river to ambush drunk Hessian troops. Saves the entire Revolution.', 'stories/washington-crosses-the-delaware/cover.webp', 255, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-yorktown-surrender', 'history-tea', 's-ht-enlightenment-and-revolutions', 'The Surrender at Yorktown', 'yorktown-surrender', 'Trapped between Washington''s army and the French navy, the British surrender. The band reportedly plays ''The World Turned Upside Down.''', 'stories/yorktown-surrender/cover.webp', 256, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-bastille', 'history-tea', 's-ht-enlightenment-and-revolutions', 'Storming the Bastille', 'storming-the-bastille', 'A Paris mob breaks into a royal prison, finds only seven prisoners (none of them political), and kicks off the French Revolution anyway.', 'stories/storming-the-bastille/cover.webp', 257, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-marie-antoinette', 'history-tea', 's-ht-enlightenment-and-revolutions', 'Marie Antoinette''s Execution', 'marie-antoinettes-execution', 'The queen who probably never said ''let them eat cake'' is paraded through Paris in a cart and beheaded. She apologizes to the executioner for stepping on his foot.', 'stories/marie-antoinettes-execution/cover.webp', 258, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-reign-of-terror', 'history-tea', 's-ht-enlightenment-and-revolutions', 'The Reign of Terror', 'reign-of-terror', 'The French Revolution starts eating its own. Robespierre sends thousands to the guillotine, then it''s his turn. The blade is impartial.', 'stories/reign-of-terror/cover.webp', 259, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-haitian-revolution', 'history-tea', 's-ht-enlightenment-and-revolutions', 'The Haitian Revolution', 'haitian-revolution', 'Enslaved people in France''s richest colony rise up, defeat Napoleon''s army, and found the first free Black republic. Then France charges them for it.', 'stories/haitian-revolution/cover.webp', 260, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-napoleon', 'history-tea', 's-ht-napoleonic-era', 'Napoleon''s Rise', 'napoleons-rise', 'A short Corsican gunner artillery officer climbs from nothing to Emperor of France in ten years. Then conquers most of Europe to celebrate.', 'stories/napoleons-rise/cover.webp', 261, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-napoleon-crowns-himself', 'history-tea', 's-ht-napoleonic-era', 'Napoleon Crowns Himself', 'napoleon-crowns-himself', 'At his own coronation, Napoleon takes the crown out of the Pope''s hands and puts it on his own head. The Pope is just there for decoration.', 'stories/napoleon-crowns-himself/cover.webp', 262, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-trafalgar', 'history-tea', 's-ht-napoleonic-era', 'The Battle of Trafalgar', 'battle-of-trafalgar', 'Admiral Nelson destroys the combined French and Spanish fleet, saving Britain from invasion. He gets shot dead in the moment of victory.', 'stories/battle-of-trafalgar/cover.webp', 263, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-austerlitz', 'history-tea', 's-ht-napoleonic-era', 'The Battle of Austerlitz', 'battle-of-austerlitz', 'Three emperors, one battlefield. Napoleon lures Russia and Austria onto frozen lakes, blows up the ice with cannons, and wins his masterpiece.', 'stories/battle-of-austerlitz/cover.webp', 264, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-napoleon-invades-russia', 'history-tea', 's-ht-napoleonic-era', 'Napoleon Invades Russia', 'napoleon-invades-russia', 'He marches in with 600,000 men. The Russians burn everything as they retreat. Six months later 100,000 frozen survivors stagger out.', 'stories/napoleon-invades-russia/cover.webp', 265, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-waterloo', 'history-tea', 's-ht-napoleonic-era', 'The Battle of Waterloo', 'battle-of-waterloo', 'Back from exile, Napoleon rolls the dice one last time. Wellington and the Prussians end his career on a muddy Belgian field in a single afternoon.', 'stories/battle-of-waterloo/cover.webp', 266, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-napoleon-at-st-helena', 'history-tea', 's-ht-napoleonic-era', 'Napoleon at St. Helena', 'napoleon-at-st-helena', 'Britain dumps Napoleon on a tiny rock in the South Atlantic. He spends six years complaining about the weather and dies of stomach cancer (or arsenic).', 'stories/napoleon-at-st-helena/cover.webp', 267, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-war-of-1812', 'history-tea', 's-ht-napoleonic-era', 'The War of 1812', 'war-of-1812', 'The British invade Washington and burn down the White House. Andrew Jackson wins New Orleans two weeks after the war is technically over.', 'stories/war-of-1812/cover.webp', 268, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-simon-bolivar-liberates', 'history-tea', 's-ht-napoleonic-era', 'Simón Bolívar Liberates Latin America', 'simon-bolivar-liberates', 'One man crosses the Andes, leads armies for 16 years, and frees six countries from Spanish rule. Then dies disillusioned and broke.', 'stories/simon-bolivar-liberates/cover.webp', 269, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-monroe-doctrine', 'history-tea', 's-ht-napoleonic-era', 'The Monroe Doctrine', 'monroe-doctrine', 'The young United States tells Europe to stay out of the entire Western Hemisphere. Bold for a country that can barely defend its own coast.', 'stories/monroe-doctrine/cover.webp', 270, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-trail-of-tears', 'history-tea', 's-ht-19th-century', 'The Trail of Tears', 'trail-of-tears', 'The U.S. forces 60,000 Native Americans off their ancestral land and marches them west. Thousands die on the way. A national wound that never heals.', 'stories/trail-of-tears/cover.webp', 271, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-alamo', 'history-tea', 's-ht-19th-century', 'Remember the Alamo', 'alamo', '200 Texans hold a Spanish mission against thousands of Mexican troops for 13 days. Everyone inside dies. Texas wins the war anyway.', 'stories/alamo/cover.webp', 272, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-opium-wars', 'history-tea', 's-ht-19th-century', 'The Opium Wars', 'opium-wars', 'China tries to stop British merchants from flooding the country with opium. Britain sends gunboats. China is forced to keep buying drugs at gunpoint.', 'stories/opium-wars/cover.webp', 273, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-irish-potato-famine', 'history-tea', 's-ht-19th-century', 'The Irish Potato Famine', 'irish-potato-famine', 'A potato disease wipes out the food of an entire country. A million Irish die, a million flee. Britain ships food out the whole time.', 'stories/irish-potato-famine/cover.webp', 274, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-1848-revolutions', 'history-tea', 's-ht-19th-century', 'The 1848 Revolutions', '1848-revolutions', 'Almost every European capital catches fire at once. Kings flee, constitutions are signed, and a year later most of it is rolled back.', 'stories/1848-revolutions/cover.webp', 275, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-california-gold-rush', 'history-tea', 's-ht-19th-century', 'The California Gold Rush', 'california-gold-rush', 'A guy finds gold at Sutter''s Mill. Within two years, 300,000 people are scrambling across the continent for it. San Francisco goes from village to city.', 'stories/california-gold-rush/cover.webp', 276, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-taiping-rebellion', 'history-tea', 's-ht-19th-century', 'The Taiping Rebellion', 'taiping-rebellion', 'A failed civil servant decides he''s Jesus''s brother and raises a 30 million-strong rebellion. Maybe the deadliest civil war ever fought.', 'stories/taiping-rebellion/cover.webp', 277, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-crimean-war', 'history-tea', 's-ht-19th-century', 'The Crimean War', 'crimean-war', 'Britain, France, and the Ottomans fight Russia over a holy site. Florence Nightingale invents modern nursing in the chaos.', 'stories/crimean-war/cover.webp', 278, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-perry-opens-japan', 'history-tea', 's-ht-19th-century', 'Perry Opens Japan', 'perry-opens-japan', 'An American admiral sails black warships into Tokyo Bay and politely asks Japan to start trading. After 250 years of isolation, Japan says yes at gunpoint.', 'stories/perry-opens-japan/cover.webp', 279, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-sepoy-mutiny', 'history-tea', 's-ht-19th-century', 'The Sepoy Mutiny', 'sepoy-mutiny', 'Indian soldiers in the British East India Company revolt over rifle cartridges greased with cow and pig fat. The British Crown takes over India directly.', 'stories/sepoy-mutiny/cover.webp', 280, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-darwin-publishes-origin', 'history-tea', 's-ht-19th-century', 'Darwin Publishes the Origin', 'darwin-publishes-origin', 'A quiet English naturalist publishes a book about finches and accidentally rewrites how humans understand themselves.', 'stories/darwin-publishes-origin/cover.webp', 281, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-italian-unification', 'history-tea', 's-ht-19th-century', 'Italian Unification', 'italian-unification', 'Garibaldi and his red-shirted thousand sail south, conquer Sicily and Naples, and hand it all to a king. Italy becomes a country for the first time.', 'stories/italian-unification/cover.webp', 282, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-german-unification', 'history-tea', 's-ht-19th-century', 'German Unification', 'german-unification', 'Bismarck stitches together 39 squabbling German states by starting and winning three wars in a row. Crowns the King of Prussia in Versailles for spite.', 'stories/german-unification/cover.webp', 283, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-lincoln-elected', 'history-tea', 's-ht-american-civil-war', 'Lincoln is Elected', 'lincoln-elected', 'An anti-slavery lawyer from Illinois wins the presidency and seven Southern states immediately walk out. The Union starts to break.', 'stories/lincoln-elected/cover.webp', 284, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-fort-sumter', 'history-tea', 's-ht-american-civil-war', 'Fort Sumter Falls', 'fort-sumter', 'Confederate cannons open fire on a federal fort in Charleston Harbor. 34 hours later, the fort surrenders. The Civil War has begun.', 'stories/fort-sumter/cover.webp', 285, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-emancipation-proclamation', 'history-tea', 's-ht-american-civil-war', 'The Emancipation Proclamation', 'emancipation-proclamation', 'Lincoln declares enslaved people in rebel states to be free. The war is no longer about preserving the Union. It''s about ending slavery.', 'stories/emancipation-proclamation/cover.webp', 286, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-gettysburg', 'history-tea', 's-ht-american-civil-war', 'The Battle of Gettysburg', 'battle-of-gettysburg', 'Three days, 50,000 casualties, and Pickett''s Charge into a meat grinder. The South never recovers. Lincoln gives a 272-word speech about it.', 'stories/battle-of-gettysburg/cover.webp', 287, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-shermans-march', 'history-tea', 's-ht-american-civil-war', 'Sherman''s March to the Sea', 'shermans-march', 'A Union general burns a 60-mile-wide path of destruction from Atlanta to Savannah to break the South''s will to fight. It works.', 'stories/shermans-march/cover.webp', 288, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-lee-surrenders-at-appomattox', 'history-tea', 's-ht-american-civil-war', 'Lee Surrenders at Appomattox', 'lee-surrenders-at-appomattox', 'Two generals meet in a farmhouse parlor. Grant lets Lee''s men keep their horses and go home. The war is finally over.', 'stories/lee-surrenders-at-appomattox/cover.webp', 289, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-lincoln-assassinated', 'history-tea', 's-ht-american-civil-war', 'Lincoln is Assassinated', 'lincoln-assassinated', 'Five days after Appomattox, an actor sneaks into the President''s box at Ford''s Theatre and shoots him in the head. The country never recovers.', 'stories/lincoln-assassinated/cover.webp', 290, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-scramble-for-africa', 'history-tea', 's-ht-imperialism-and-late-1800s', 'The Scramble for Africa', 'scramble-for-africa', 'European powers gather around a map in Berlin and carve up an entire continent over brandy. They draw lines that still cause wars today.', 'stories/scramble-for-africa/cover.webp', 291, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-isandlwana', 'history-tea', 's-ht-imperialism-and-late-1800s', 'The Battle of Isandlwana', 'battle-of-isandlwana', 'Zulu warriors with spears destroy a fully equipped British army. Britain is so humiliated it spends the rest of the year hunting down a king.', 'stories/battle-of-isandlwana/cover.webp', 292, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-rorkes-drift', 'history-tea', 's-ht-imperialism-and-late-1800s', 'Rorke''s Drift', 'rorkes-drift', '150 British soldiers hold a tiny mission station against 4,000 Zulus through the night. Eleven Victoria Crosses awarded. Britain calls it victory.', 'stories/rorkes-drift/cover.webp', 293, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-meiji-restoration', 'history-tea', 's-ht-imperialism-and-late-1800s', 'The Meiji Restoration', 'meiji-restoration', 'Japan ends 700 years of samurai rule, restores the Emperor, and modernizes faster than any country ever has. In 30 years it goes from feudal to industrial.', 'stories/meiji-restoration/cover.webp', 294, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-little-bighorn', 'history-tea', 's-ht-imperialism-and-late-1800s', 'The Battle of Little Bighorn', 'battle-of-little-bighorn', 'Custer charges a vastly larger Lakota and Cheyenne force and gets every single one of his men killed. Sitting Bull''s last great victory.', 'stories/battle-of-little-bighorn/cover.webp', 295, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-wounded-knee', 'history-tea', 's-ht-imperialism-and-late-1800s', 'Wounded Knee', 'wounded-knee', 'U.S. cavalry massacres about 250 Lakota men, women, and children in a South Dakota creek bed. The end of the Indian Wars.', 'stories/wounded-knee/cover.webp', 296, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-spanish-american-war', 'history-tea', 's-ht-imperialism-and-late-1800s', 'The Spanish-American War', 'spanish-american-war', 'The USS Maine explodes in Havana harbor. Newspapers blame Spain. Four months later America has Cuba, Puerto Rico, the Philippines, and Guam.', 'stories/spanish-american-war/cover.webp', 297, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-boxer-rebellion', 'history-tea', 's-ht-imperialism-and-late-1800s', 'The Boxer Rebellion', 'boxer-rebellion', 'A Chinese martial arts cult tries to expel all foreigners. Eight foreign armies march into Beijing together to crush it. China is humiliated again.', 'stories/boxer-rebellion/cover.webp', 298, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-russo-japanese-war', 'history-tea', 's-ht-imperialism-and-late-1800s', 'The Russo-Japanese War', 'russo-japanese-war', 'Tiny modernized Japan annihilates a Russian fleet at Tsushima. First time in centuries an Asian power beats a European one. Russia is so humiliated it has a revolution.', 'stories/russo-japanese-war/cover.webp', 299, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-titanic', 'history-tea', 's-ht-world-war-i', 'The Titanic Sinks', 'titanic-sinks', 'The ''unsinkable'' ship hits an iceberg on its maiden voyage. Not enough lifeboats. 1,500 people die in the freezing North Atlantic.', 'stories/titanic-sinks/cover.webp', 300, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-franz-ferdinand', 'history-tea', 's-ht-world-war-i', 'Archduke Franz Ferdinand is Shot', 'archduke-franz-ferdinand', 'A teenager in Sarajevo shoots an Austrian heir on the world''s worst-routed motorcade. Six weeks later, the entire planet is at war.', 'stories/archduke-franz-ferdinand/cover.webp', 301, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-christmas-truce-1914', 'history-tea', 's-ht-world-war-i', 'The Christmas Truce', 'christmas-truce-1914', 'On Christmas Eve in the trenches, German soldiers start singing carols. British soldiers join in. They climb out and play soccer. The next day they''re shooting again.', 'stories/christmas-truce-1914/cover.webp', 302, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-gallipoli', 'history-tea', 's-ht-world-war-i', 'Gallipoli', 'gallipoli', 'An Allied plan to knock the Ottomans out of the war turns into eight months of carnage on a Turkish beach. Australia and New Zealand are still grieving.', 'stories/gallipoli/cover.webp', 303, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-lusitania-sinks', 'history-tea', 's-ht-world-war-i', 'The Lusitania Sinks', 'lusitania-sinks', 'A German U-boat torpedoes a passenger liner off Ireland. 1,200 dead, including 128 Americans. America starts thinking about joining the war.', 'stories/lusitania-sinks/cover.webp', 304, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-verdun', 'history-tea', 's-ht-world-war-i', 'The Battle of Verdun', 'battle-of-verdun', 'Ten months of meat-grinder warfare for almost no ground. 700,000 casualties. The bones are still being collected.', 'stories/battle-of-verdun/cover.webp', 305, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-the-somme', 'history-tea', 's-ht-world-war-i', 'The Battle of the Somme', 'battle-of-the-somme', 'On day one, 19,000 British soldiers die. Most of them in the first hour. The battle drags on for four more months.', 'stories/battle-of-the-somme/cover.webp', 306, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-russian-revolution', 'history-tea', 's-ht-world-war-i', 'The Russian Revolution', 'russian-revolution', 'A bread riot in Petrograd brings down the tsar in a week. Lenin returns from exile in a sealed train. Russia is suddenly Soviet.', 'stories/russian-revolution/cover.webp', 307, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-tsar-and-family-shot', 'history-tea', 's-ht-world-war-i', 'The Tsar and His Family Are Shot', 'tsar-and-family-shot', 'Nicholas II, his wife, four daughters, and son are taken to a basement in Yekaterinburg and executed. The Romanov dynasty ends after 304 years.', 'stories/tsar-and-family-shot/cover.webp', 308, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-treaty-of-versailles', 'history-tea', 's-ht-world-war-i', 'The Treaty of Versailles', 'treaty-of-versailles', 'The Allies blame Germany for everything and stick it with crippling reparations. One French marshal says: ''This is not peace. It is an armistice for 20 years.''', 'stories/treaty-of-versailles/cover.webp', 309, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-spanish-flu', 'history-tea', 's-ht-interwar-era', 'The Spanish Flu', 'spanish-flu', 'A virus rides the troopships home and kills 50 million people in two years. More than the war that just ended.', 'stories/spanish-flu/cover.webp', 310, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-roaring-twenties', 'history-tea', 's-ht-interwar-era', 'The Roaring Twenties', 'roaring-twenties', 'Jazz, flappers, bootleg gin, and a stock market that only goes up. Everyone''s having fun until they''re not.', 'stories/roaring-twenties/cover.webp', 311, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-stock-market-crash-1929', 'history-tea', 's-ht-interwar-era', 'The Stock Market Crashes', 'stock-market-crash-1929', 'On Black Tuesday, the market loses billions in a single day. Bankers jump out of windows. The world plunges into the Great Depression.', 'stories/stock-market-crash-1929/cover.webp', 312, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-hitler-rises', 'history-tea', 's-ht-interwar-era', 'Hitler Rises to Power', 'hitler-rises', 'A failed Austrian painter and former corporal becomes Chancellor of Germany through the ballot box. Within months he has absolute power.', 'stories/hitler-rises/cover.webp', 313, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-stalins-purges', 'history-tea', 's-ht-interwar-era', 'Stalin''s Purges', 'stalins-purges', 'Stalin executes or exiles his own officers, party members, scientists, even photographers who took the wrong photo. Millions disappear.', 'stories/stalins-purges/cover.webp', 314, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-long-march', 'history-tea', 's-ht-interwar-era', 'Mao''s Long March', 'long-march', 'Chinese Communists retreat 6,000 miles through mountains and deserts to escape destruction. Only 1 in 10 survive. Mao emerges as undisputed leader.', 'stories/long-march/cover.webp', 315, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-spanish-civil-war', 'history-tea', 's-ht-interwar-era', 'The Spanish Civil War', 'spanish-civil-war', 'Fascists, Republicans, anarchists, and communists tear Spain apart for three years. Hitler and Mussolini test their bombers on civilians.', 'stories/spanish-civil-war/cover.webp', 316, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-munich-agreement', 'history-tea', 's-ht-interwar-era', 'The Munich Agreement', 'munich-agreement', 'Britain and France hand Hitler a chunk of Czechoslovakia in exchange for a promise. Chamberlain comes home waving a paper: ''Peace for our time.'' It is not.', 'stories/munich-agreement/cover.webp', 317, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-invasion-of-poland', 'history-tea', 's-ht-world-war-ii', 'The Invasion of Poland', 'invasion-of-poland', 'On September 1, German tanks pour across the border. Two days later, Britain and France declare war. WWII has begun.', 'stories/invasion-of-poland/cover.webp', 318, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-fall-of-france', 'history-tea', 's-ht-world-war-ii', 'The Fall of France', 'fall-of-france', 'German blitzkrieg goes around the Maginot Line. France falls in six weeks. Hitler dances a little jig in front of the Eiffel Tower.', 'stories/fall-of-france/cover.webp', 319, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-dunkirk-evacuation', 'history-tea', 's-ht-world-war-ii', 'The Dunkirk Evacuation', 'dunkirk-evacuation', 'Trapped against the sea, 338,000 British and French soldiers are rescued by a flotilla of Navy ships and civilian fishing boats. A defeat that feels like a miracle.', 'stories/dunkirk-evacuation/cover.webp', 320, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-britain', 'history-tea', 's-ht-world-war-ii', 'The Battle of Britain', 'battle-of-britain', 'RAF pilots in Spitfires hold off the German air force in the skies over England. Churchill: ''Never was so much owed by so many to so few.''', 'stories/battle-of-britain/cover.webp', 321, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-operation-barbarossa', 'history-tea', 's-ht-world-war-ii', 'Operation Barbarossa', 'operation-barbarossa', 'Hitler invades the Soviet Union with 3 million men. The largest invasion in history. He thinks it''ll take three months. It takes everything he has.', 'stories/operation-barbarossa/cover.webp', 322, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-pearl-harbor', 'history-tea', 's-ht-world-war-ii', 'Pearl Harbor', 'pearl-harbor', 'On a quiet Sunday morning, Japanese carriers launch a surprise attack on the U.S. Pacific Fleet. America wakes up at war.', 'stories/pearl-harbor/cover.webp', 323, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-the-holocaust', 'history-tea', 's-ht-world-war-ii', 'The Holocaust', 'the-holocaust', 'Nazi Germany industrially murders six million Jews and millions of others. The darkest organized crime in human history.', 'stories/the-holocaust/cover.webp', 324, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-midway', 'history-tea', 's-ht-world-war-ii', 'The Battle of Midway', 'midway', 'American codebreakers know exactly where Japan is going. U.S. dive bombers sink four Japanese carriers in five minutes. The Pacific war turns.', 'stories/midway/cover.webp', 325, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-stalingrad', 'history-tea', 's-ht-world-war-ii', 'The Battle of Stalingrad', 'stalingrad', 'Five months of street-to-street fighting in a frozen ruined city. Two million casualties. Germany''s army gets surrounded and surrenders.', 'stories/stalingrad/cover.webp', 326, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-d-day', 'history-tea', 's-ht-world-war-ii', 'D-Day', 'd-day', 'On June 6, 156,000 Allied troops storm five beaches in Normandy. The largest amphibious invasion ever. The beginning of the end for Hitler.', 'stories/d-day/cover.webp', 327, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-warsaw-uprising', 'history-tea', 's-ht-world-war-ii', 'The Warsaw Uprising', 'warsaw-uprising', 'The Polish Home Army rises up to free their own capital. They hold out for 63 days. The Red Army across the river watches and does nothing.', 'stories/warsaw-uprising/cover.webp', 328, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-battle-of-the-bulge', 'history-tea', 's-ht-world-war-ii', 'The Battle of the Bulge', 'battle-of-the-bulge', 'Hitler''s last big gamble. He hits the Allies in the freezing Ardennes during Christmas. Surrounded in Bastogne, the Americans answer surrender demands with one word: ''Nuts.''', 'stories/battle-of-the-bulge/cover.webp', 329, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-fall-of-berlin', 'history-tea', 's-ht-world-war-ii', 'The Fall of Berlin', 'fall-of-berlin', 'The Red Army storms the Reichstag. Hitler shoots himself in a bunker beneath the city. The Soviet flag goes up over Berlin.', 'stories/fall-of-berlin/cover.webp', 330, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-hiroshima', 'history-tea', 's-ht-world-war-ii', 'Hiroshima and Nagasaki', 'hiroshima-and-nagasaki', 'Two atomic bombs vaporize two Japanese cities in three days. Over 200,000 people die. Japan surrenders. The nuclear age begins.', 'stories/hiroshima-and-nagasaki/cover.webp', 331, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-nuremberg-trials', 'history-tea', 's-ht-world-war-ii', 'The Nuremberg Trials', 'nuremberg-trials', 'Top Nazi leaders are put on trial in their own former rally city. ''I was just following orders'' is rejected as a defense. Modern war crimes law is born.', 'stories/nuremberg-trials/cover.webp', 332, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-iron-curtain', 'history-tea', 's-ht-cold-war', 'The Iron Curtain Falls', 'iron-curtain', 'Churchill warns the world that Stalin has dropped a curtain across Europe. The Cold War is officially named.', 'stories/iron-curtain/cover.webp', 333, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-partition-of-india', 'history-tea', 's-ht-cold-war', 'The Partition of India', 'partition-of-india', 'Britain leaves India in a hurry. A line is drawn on a map by a man who''s never been there. 15 million people flee in both directions and a million die.', 'stories/partition-of-india/cover.webp', 334, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-founding-of-israel', 'history-tea', 's-ht-cold-war', 'The Founding of Israel', 'founding-of-israel', 'Three years after the Holocaust, the State of Israel is declared. Five Arab armies invade the next day. The conflict has not ended since.', 'stories/founding-of-israel/cover.webp', 335, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-berlin-airlift', 'history-tea', 's-ht-cold-war', 'The Berlin Airlift', 'berlin-airlift', 'Stalin blockades West Berlin. The U.S. and Britain fly in 2.3 million tons of supplies, sometimes one plane every 30 seconds, for almost a year. Stalin gives up.', 'stories/berlin-airlift/cover.webp', 336, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-mao-founds-prc', 'history-tea', 's-ht-cold-war', 'Mao Founds the People''s Republic', 'mao-founds-prc', 'After 22 years of civil war, Mao stands on a balcony in Beijing and declares China is now Communist. The losing side flees to Taiwan.', 'stories/mao-founds-prc/cover.webp', 337, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-korean-war', 'history-tea', 's-ht-cold-war', 'The Korean War', 'korean-war', 'The North invades the South. The U.S. counterattacks. China sends a million ''volunteers.'' Three years later, everyone stops on roughly the same line they started on.', 'stories/korean-war/cover.webp', 338, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-hungarian-revolution', 'history-tea', 's-ht-cold-war', 'The Hungarian Revolution', 'hungarian-revolution', 'Hungarians topple the Soviet-backed government in 13 days. Then 200,000 Soviet troops and 2,500 tanks roll in. The West does nothing.', 'stories/hungarian-revolution/cover.webp', 339, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-sputnik-launches', 'history-tea', 's-ht-cold-war', 'Sputnik Launches', 'sputnik-launches', 'A beach ball-sized Soviet satellite goes ''beep'' from orbit. America panics, dumps money into NASA, and the Space Race is on.', 'stories/sputnik-launches/cover.webp', 340, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-cuban-missile-crisis', 'history-tea', 's-ht-cold-war', 'The Cuban Missile Crisis', 'cuban-missile-crisis', 'Soviet nukes appear 90 miles off the Florida coast. For 13 days, JFK and Khrushchev play chicken with the end of the world. Khrushchev blinks first.', 'stories/cuban-missile-crisis/cover.webp', 341, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-jfk-assassinated', 'history-tea', 's-ht-cold-war', 'JFK is Assassinated', 'jfk-assassinated', 'In Dallas, Texas, the President is shot from a book depository window. The accused shooter is killed two days later on live TV. The conspiracy theories never stop.', 'stories/jfk-assassinated/cover.webp', 342, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-mlk-i-have-a-dream', 'history-tea', 's-ht-cold-war', 'Martin Luther King''s ''I Have a Dream''', 'mlk-i-have-a-dream', 'On the steps of the Lincoln Memorial, MLK delivers the most famous speech in American history. 250,000 people listen in silence.', 'stories/mlk-i-have-a-dream/cover.webp', 343, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-vietnam-war', 'history-tea', 's-ht-cold-war', 'The Vietnam War', 'vietnam-war', 'The U.S. spends 20 years, 58,000 lives, and immense moral capital trying to stop South Vietnam from going Communist. It goes Communist anyway.', 'stories/vietnam-war/cover.webp', 344, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-moon-landing', 'history-tea', 's-ht-cold-war', 'The Moon Landing', 'moon-landing', 'On July 20, Neil Armstrong steps off a ladder onto another world. 600 million people on Earth hold their breath. ''One small step…''', 'stories/moon-landing/cover.webp', 345, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-watergate', 'history-tea', 's-ht-cold-war', 'Watergate', 'watergate', 'A bungled break-in at a Washington hotel ends with a U.S. President resigning before he can be impeached. Two journalists become legends.', 'stories/watergate/cover.webp', 346, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-fall-of-saigon', 'history-tea', 's-ht-cold-war', 'The Fall of Saigon', 'fall-of-saigon', 'American helicopters lift the last people off the embassy roof while North Vietnamese tanks crash through the gates. The Vietnam War ends.', 'stories/fall-of-saigon/cover.webp', 347, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-iran-hostage-crisis', 'history-tea', 's-ht-cold-war', 'The Iran Hostage Crisis', 'iran-hostage-crisis', 'Iranian students storm the U.S. embassy and hold 52 Americans for 444 days. A failed rescue mission ends in flames in the desert.', 'stories/iran-hostage-crisis/cover.webp', 348, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-berlin-wall', 'history-tea', 's-ht-cold-war', 'The Fall of the Berlin Wall', 'fall-of-the-berlin-wall', 'An East German official misreads a memo on live TV. Within hours, thousands of Berliners are tearing the wall down with hammers. The Cold War is essentially over.', 'stories/fall-of-the-berlin-wall/cover.webp', 349, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-tiananmen-square', 'history-tea', 's-ht-modern-era', 'Tiananmen Square', 'tiananmen-square', 'Chinese troops clear a protest in the heart of Beijing with tanks and live rounds. One man stands alone in front of a column of tanks. Nobody knows his name.', 'stories/tiananmen-square/cover.webp', 350, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-soviet-collapse', 'history-tea', 's-ht-modern-era', 'The Soviet Union Collapses', 'soviet-collapse', 'On Christmas Day, the hammer and sickle is lowered over the Kremlin for the last time. 15 new countries are born overnight.', 'stories/soviet-collapse/cover.webp', 351, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-mandela-freed', 'history-tea', 's-ht-modern-era', 'Mandela Walks Free', 'mandela-freed', 'After 27 years in prison, Nelson Mandela walks out of Victor Verster prison and into history. Four years later he''s President of South Africa.', 'stories/mandela-freed/cover.webp', 352, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-rwandan-genocide', 'history-tea', 's-ht-modern-era', 'The Rwandan Genocide', 'rwandan-genocide', 'In 100 days, neighbors murder neighbors with machetes. 800,000 dead. The world watches and does almost nothing.', 'stories/rwandan-genocide/cover.webp', 353, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-yugoslav-wars', 'history-tea', 's-ht-modern-era', 'The Yugoslav Wars', 'yugoslav-wars', 'A multi-ethnic country tears itself apart along religious and ethnic lines. The word ''genocide'' returns to Europe for the first time since WWII.', 'stories/yugoslav-wars/cover.webp', 354, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-9-11', 'history-tea', 's-ht-modern-era', 'September 11', '9-11', 'Hijacked planes hit the Twin Towers and the Pentagon. A fourth crashes in a Pennsylvania field. The world after this morning is a different one.', 'stories/9-11/cover.webp', 355, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-iraq-war', 'history-tea', 's-ht-modern-era', 'The Iraq War', 'iraq-war', 'The U.S. invades Iraq looking for weapons that aren''t there. Topples Saddam in three weeks. Spends the next decade trying to leave.', 'stories/iraq-war/cover.webp', 356, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-financial-crisis-2008', 'history-tea', 's-ht-modern-era', 'The 2008 Financial Crisis', 'financial-crisis-2008', 'Wall Street''s bet on bad mortgages blows up. Lehman Brothers vanishes overnight. The whole global economy nearly goes with it.', 'stories/financial-crisis-2008/cover.webp', 357, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-arab-spring', 'history-tea', 's-ht-modern-era', 'The Arab Spring', 'arab-spring', 'A Tunisian street vendor sets himself on fire. Within months, dictators across the Arab world are falling. Then it gets complicated.', 'stories/arab-spring/cover.webp', 358, 1, 1);
INSERT OR IGNORE INTO stories (id, app_id, season_id, title, slug, description, cover_image_key, sort_order, is_free, is_published) VALUES ('st-covid-19-pandemic', 'history-tea', 's-ht-modern-era', 'The COVID-19 Pandemic', 'covid-19-pandemic', 'A virus from a market in Wuhan locks down the entire planet. Millions die. The world learns the word ''unprecedented'' the hard way.', 'stories/covid-19-pandemic/cover.webp', 359, 1, 1);

